import org.apache.kafka.common.utils.BufferSupplier;
import org.apache.kafka.common.utils.ByteBufferOutputStream;
import org.apache.kafka.common.utils.CloseableIterator;
import org.apache.kafka.common.utils.Utils;

import java.io.IOException;
import java.nio.ByteBuffer;
import java.nio.channels.GatheringByteChannel;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.Objects;

/**
 * An in-memory collection of {@link RecordBatch} instances backed by a {@link ByteBuffer}.
 *
 * <p><b>Purpose:</b> This class provides a read/write view over a buffer containing one or more
 * serialized record batches. It is used for:
 * <ul>
 *   <li>Parsing incoming produce requests from clients</li>
 *   <li>Reading/modifying batches in the log</li>
 *   <li>Filtering and compacting log segments</li>
 *   <li>Transmitting batches over the network</li>
 * </ul>
 *
 * <p><b>Memory Layout:</b> The buffer contains a sequence of concatenated batches. Each batch
 * begins with a base offset (8 bytes) followed by the batch length (4 bytes), allowing sequential
 * iteration. Use {@link #batchIterator()} to parse batches lazily without loading all data
 * into memory.
 *
 * <p><b>Thread Safety:</b> This class is not thread-safe. The underlying {@link ByteBuffer}
 * is not protected from concurrent access. Multiple threads must not access the same
 * {@code MemoryRecords} instance concurrently. Iterators and filtered results are also
 * not thread-safe.
 *
 * <p><b>Lazy Evaluation:</b> Batch parsing is performed lazily when batches are requested.
 * No validation or decompression occurs until {@link #batchIterator()}, {@link #batches()},
 * or {@link #filterTo(RecordFilter, ByteBuffer, BufferSupplier)} is called.
 *
 * <p><b>Buffer Ownership:</b> {@code MemoryRecords} does not take ownership of the backing
 * buffer. The caller is responsible for managing the buffer's lifecycle and ensuring it
 * remains valid while the {@code MemoryRecords} instance is in use.
 *
 * <p><b>Creating Records:</b> Use the factory methods {@link #builder(ByteBuffer, Compression, TimestampType, long)}
 * or {@link #withRecords(Compression, SimpleRecord...)} to create new batches. These return
 * a {@link MemoryRecordsBuilder} for efficient batch construction.
 *
 * <p><b>Filtering and Compaction:</b> The {@link #filterTo(RecordFilter, ByteBuffer, BufferSupplier)}
 * method supports log compaction and retention filtering. It handles compressed batches,
 * empty batches, and delete horizon markers. Filters can specify batch-level retention
 * decisions or examine individual records.
 *
 * @see RecordBatch
 * @see DefaultRecordBatch
 * @see MemoryRecordsBuilder
 * @see Records
 */
public class MemoryRecords extends AbstractRecords {
    /**
     * An empty {@code MemoryRecords} instance backed by an empty buffer.
     */
    public static final MemoryRecords EMPTY = MemoryRecords.readableRecords(ByteBuffer.allocate(0));

    private final ByteBuffer buffer;

    private final Iterable<MutableRecordBatch> batches = this::batchIterator;

    private int validBytes = -1;

    // Construct a writable memory records
    /**
     * Create a {@code MemoryRecords} instance backed by the given buffer.
     *
     * <p>The buffer must contain valid record batch data (or be empty). The buffer's position,
     * limit, and content must not be modified externally while this instance is in use.
     *
     * @param buffer A {@link ByteBuffer} containing serialized record batches. Cannot be null.
     * @throws NullPointerException if buffer is null
     */
    private MemoryRecords(ByteBuffer buffer) {
        Objects.requireNonNull(buffer, "buffer should not be null");
        this.buffer = buffer;
    }

    @Override
    public int sizeInBytes() {
        return buffer.limit();
    }

    @Override
    public int writeTo(TransferableChannel channel, int position, int length) throws IOException {
        if (((long) position) + length > buffer.limit())
            throw new IllegalArgumentException("position+length should not be greater than buffer.limit(), position: "
                    + position + ", length: " + length + ", buffer.limit(): " + buffer.limit());

        return Utils.tryWriteTo(channel, position, length, buffer);
    }

    /**
     * Write all records to the given channel (including partial records).
     *
     * <p>This method writes the entire buffer to the channel, potentially in multiple writes
     * if the channel cannot accept all data at once. The buffer is temporarily marked and
     * reset to preserve its state.
     *
     * @param channel The channel to write to
     * @return The total number of bytes written
     * @throws IOException For any IO errors writing to the channel
     */
    public int writeFullyTo(GatheringByteChannel channel) throws IOException {
        buffer.mark();
        int written = 0;
        while (written < sizeInBytes())
            written += channel.write(buffer);
        buffer.reset();
        return written;
    }

    /**
     * The total number of bytes in this message set not including any partial, trailing messages.
     *
     * <p>This may be smaller than what is returned by {@link #sizeInBytes()} if the buffer
     * ends with an incomplete batch header. This method iterates all batches to compute the
     * valid byte count and caches the result.
     *
     * @return The number of valid bytes
     */
    public int validBytes() {
        if (validBytes >= 0)
            return validBytes;

        int bytes = 0;
        for (RecordBatch batch : batches())
            bytes += batch.sizeInBytes();

        this.validBytes = bytes;
        return bytes;
    }

    @Override
    public AbstractIterator<MutableRecordBatch> batchIterator() {
        return new RecordBatchIterator<>(new ByteBufferLogInputStream(buffer.duplicate(), Integer.MAX_VALUE));
    }

    /**
     * Validates the header of the first batch and returns its size.
     *
     * <p>This method reads only the batch header (up to the magic byte and length field)
     * without validating the full batch or decompressing records.
     *
     * @return First batch size including {@link Records#LOG_OVERHEAD} if buffer contains
     *         header up to magic byte, {@code null} if insufficient data
     * @throws CorruptRecordException if the record size or magic value is invalid
     */
    public Integer firstBatchSize() {
        if (buffer.remaining() < HEADER_SIZE_UP_TO_MAGIC)
            return null;
        return new ByteBufferLogInputStream(buffer, Integer.MAX_VALUE).nextBatchSize();
    }

    /**
     * Filter the records into the provided ByteBuffer.
     *
     * <p>This method processes each batch in the buffer, applying a user-provided filter to
     * determine which records to retain. It handles:
     * <ul>
     *   <li>Batch-level filtering decisions (delete entire batch, retain if empty, etc.)</li>
     *   <li>Record-level filtering within retained batches</li>
     *   <li>Decompression and recompression of compressed batches</li>
     *   <li>Empty batch retention for producer state preservation</li>
     *   <li>Delete horizon markers for time-based retention</li>
     * </ul>
     *
     * <p>The filter is called for each batch and potentially each record. Implementations
     * should be efficient as they are called on every log compaction.
     *
     * @param filter The filter function that determines which batches and records to retain
     * @param destinationBuffer The byte buffer to write the filtered records to. Must have
     *                           sufficient capacity or be resizable.
     * @param decompressionBufferSupplier The supplier of ByteBuffer(s) used for decompression
     *                                     if supported. For small record batches, allocating a
     *                                     potentially large buffer (64 KB for LZ4) will dominate
     *                                     the cost of decompressing and iterating. A supplier
     *                                     that reuses buffers will have significant performance
     *                                     impact.
     * @return A {@link FilterResult} with a summary of the output (for metrics) and potentially
     *         an overflow buffer if the destination was too small
     * @see RecordFilter
     * @see FilterResult
     */
    public FilterResult filterTo(RecordFilter filter, ByteBuffer destinationBuffer, BufferSupplier decompressionBufferSupplier) {
        return filterTo(batches(), filter, destinationBuffer, decompressionBufferSupplier);
    }

    /**
     * Note: This method is also used to convert the first timestamp of the batch (which is usually the timestamp of the first record)
     * to the delete horizon of the tombstones or txn markers which are present in the batch.
     */
    private static FilterResult filterTo(Iterable<MutableRecordBatch> batches, RecordFilter filter,
                                         ByteBuffer destinationBuffer, BufferSupplier decompressionBufferSupplier) {
        FilterResult filterResult = new FilterResult(destinationBuffer);
        ByteBufferOutputStream bufferOutputStream = new ByteBufferOutputStream(destinationBuffer);
        for (MutableRecordBatch batch : batches) {
            final BatchRetentionResult batchRetentionResult = filter.checkBatchRetention(batch);
            final boolean containsMarkerForEmptyTxn = batchRetentionResult.containsMarkerForEmptyTxn;
            final BatchRetention batchRetention = batchRetentionResult.batchRetention;

            filterResult.bytesRead += batch.sizeInBytes();

            if (batchRetention == BatchRetention.DELETE)
                continue;

            final BatchFilterResult iterationResult = filterBatch(batch, decompressionBufferSupplier, filterResult,
                filter);
            List<Record> retainedRecords = iterationResult.retainedRecords;
            boolean containsTombstones = iterationResult.containsTombstones;
            boolean writeOriginalBatch = iterationResult.writeOriginalBatch;
            long maxOffset = iterationResult.maxOffset;

            if (!retainedRecords.isEmpty()) {
                // we check if the delete horizon should be set to a new value
                // in which case, we need to reset the base timestamp and overwrite the timestamp deltas
                // if the batch does not contain tombstones, then we don't need to overwrite batch
                boolean needToSetDeleteHorizon = (containsTombstones || containsMarkerForEmptyTxn) &&
                    batch.deleteHorizonMs().isEmpty();
                if (writeOriginalBatch && !needToSetDeleteHorizon) {
                    batch.writeTo(bufferOutputStream);
                    filterResult.updateRetainedBatchMetadata(batch, retainedRecords.size(), false);
                } else {
                    long deleteHorizonMs;
                    if (needToSetDeleteHorizon)
                        deleteHorizonMs = filter.currentTime + filter.deleteRetentionMs;
                    else
                        deleteHorizonMs = batch.deleteHorizonMs().orElse(RecordBatch.NO_TIMESTAMP);
                    try (final MemoryRecordsBuilder builder = buildRetainedRecordsInto(batch, retainedRecords,
                            bufferOutputStream, deleteHorizonMs)) {
                        MemoryRecords records = builder.build();
                        int filteredBatchSize = records.sizeInBytes();
                        MemoryRecordsBuilder.RecordsInfo info = builder.info();
                        filterResult.updateRetainedBatchMetadata(info.maxTimestamp, info.shallowOffsetOfMaxTimestamp,
                            maxOffset, retainedRecords.size(), filteredBatchSize);
                    }
                }
            } else if (batchRetention == BatchRetention.RETAIN_EMPTY) {
                if (batch.magic() < RecordBatch.MAGIC_VALUE_V2) // should never happen
                    throw new IllegalStateException("Empty batches are only supported for magic v2 and above");

                bufferOutputStream.ensureRemaining(DefaultRecordBatch.RECORD_BATCH_OVERHEAD);
                DefaultRecordBatch.writeEmptyHeader(bufferOutputStream.buffer(), RecordBatch.CURRENT_MAGIC_VALUE, batch.producerId(),
                        batch.producerEpoch(), batch.baseSequence(), batch.baseOffset(), batch.lastOffset(),
                        batch.partitionLeaderEpoch(), batch.timestampType(), batch.maxTimestamp(),
                        batch.isTransactional(), batch.isControlBatch());
                filterResult.updateRetainedBatchMetadata(batch, 0, true);
            }

            // If we had to allocate a new buffer to fit the filtered buffer (see KAFKA-5316), return early to
            // avoid the need for additional allocations.
            ByteBuffer outputBuffer = bufferOutputStream.buffer();
            if (outputBuffer != destinationBuffer) {
                filterResult.outputBuffer = outputBuffer;
                return filterResult;
            }
        }

        return filterResult;
    }

    private static BatchFilterResult filterBatch(RecordBatch batch,
                                                 BufferSupplier decompressionBufferSupplier,
                                                 FilterResult filterResult,
                                                 RecordFilter filter) {
        try (final CloseableIterator<Record> iterator = batch.streamingIterator(decompressionBufferSupplier)) {
            long maxOffset = -1;
            boolean containsTombstones = false;
            // Convert records with old record versions
            boolean writeOriginalBatch = batch.magic() >= RecordBatch.CURRENT_MAGIC_VALUE;
            List<Record> retainedRecords = new ArrayList<>();
            while (iterator.hasNext()) {
                Record record = iterator.next();
                filterResult.messagesRead += 1;

                if (filter.shouldRetainRecord(batch, record)) {
                    if (record.offset() > maxOffset)
                        maxOffset = record.offset();

                    retainedRecords.add(record);

                    if (!record.hasValue()) {
                        containsTombstones = true;
                    }
                } else {
                    writeOriginalBatch = false;
                }
            }
            return new BatchFilterResult(retainedRecords, writeOriginalBatch, containsTombstones, maxOffset);
        }
    }

    private static class BatchFilterResult {
        private final List<Record> retainedRecords;
        private final boolean writeOriginalBatch;
        private final boolean containsTombstones;
        private final long maxOffset;
        private BatchFilterResult(List<Record> retainedRecords,
                                  final boolean writeOriginalBatch,
                                  final boolean containsTombstones,
                                  final long maxOffset) {
            this.retainedRecords = retainedRecords;
            this.writeOriginalBatch = writeOriginalBatch;
            this.containsTombstones = containsTombstones;
            this.maxOffset = maxOffset;
        }
    }

    private static MemoryRecordsBuilder buildRetainedRecordsInto(RecordBatch originalBatch,
                                                                 List<Record> retainedRecords,
                                                                 ByteBufferOutputStream bufferOutputStream,
                                                                 final long deleteHorizonMs) {
        Compression compression = Compression.of(originalBatch.compressionType()).build();
        // V0 has no timestamp type or timestamp, so we set the timestamp to CREATE_TIME and timestamp to NO_TIMESTAMP.
        // Note that this differs from produce up-conversion where the timestamp type topic config is used and the log append
        // time is generated if the config is LOG_APPEND_TIME. The reason for the different behavior is that there is
        // no appropriate log append time we can generate at compaction time.
        TimestampType timestampType = originalBatch.timestampType() == TimestampType.NO_TIMESTAMP_TYPE ?
                TimestampType.CREATE_TIME : originalBatch.timestampType();
        long logAppendTime = timestampType == TimestampType.LOG_APPEND_TIME ?
                originalBatch.maxTimestamp() : RecordBatch.NO_TIMESTAMP;
        long baseOffset = originalBatch.magic() >= RecordBatch.MAGIC_VALUE_V2 ?
                originalBatch.baseOffset() : retainedRecords.get(0).offset();

        // Convert records with older record versions to the current one
        MemoryRecordsBuilder builder = new MemoryRecordsBuilder(bufferOutputStream, RecordBatch.CURRENT_MAGIC_VALUE,
                compression, timestampType, baseOffset, logAppendTime, originalBatch.producerId(),
                originalBatch.producerEpoch(), originalBatch.baseSequence(), originalBatch.isTransactional(),
                originalBatch.isControlBatch(), originalBatch.partitionLeaderEpoch(), bufferOutputStream.limit(), deleteHorizonMs);

        for (Record record : retainedRecords)
            builder.append(record);

        if (originalBatch.magic() >= RecordBatch.MAGIC_VALUE_V2)
            // we must preserve the last offset from the initial batch in order to ensure that the
            // last sequence number from the batch remains even after compaction. Otherwise, the producer
            // could incorrectly see an out of sequence error.
            builder.overrideLastOffset(originalBatch.lastOffset());

        return builder;
    }

    /**
     * Get the byte buffer that backs this instance for reading.
     *
     * <p>Returns a duplicate of the backing buffer, so modifications to the returned buffer's
     * position or limit will not affect this instance, but modifications to the buffer's
     * contents will be visible.
     *
     * @return A duplicate of the backing buffer
     */
    public ByteBuffer buffer() {
        return buffer.duplicate();
    }

    @Override
    public MemoryRecords slice(int position, int size) {
        if (position < 0)
            throw new IllegalArgumentException("Invalid position: " + position + " in read from " + this);
        if (position > buffer.limit())
            throw new IllegalArgumentException("Slice from position " + position + " exceeds end position of " + this);
        if (size < 0)
            throw new IllegalArgumentException("Invalid size: " + size + " in read from " + this);

        int availableBytes = Math.min(size, buffer.limit() - position);
        // As of now, clients module support Java11 hence can't use ByteBuffer::slice(position, size) method.
        // So we need to create a duplicate buffer and set the position and limit. Duplicate buffer
        // is backed by original bytes hence not the content but only the relative position and limit
        // are changed in the duplicate buffer. Once the position and limit are set, we can call the
        // slice method to get the sliced buffer, which is a backed by the original buffer with the
        // position reset to 0 and limit set to the size of the slice.
        ByteBuffer slicedBuffer = buffer.duplicate();
        slicedBuffer.position(position);
        slicedBuffer.limit(position + availableBytes);
        // Reset the position to 0 so that the sliced view has a relative position.
        slicedBuffer = slicedBuffer.slice();

        return readableRecords(slicedBuffer);
    }

    @Override
    public Iterable<MutableRecordBatch> batches() {
        return batches;
    }

    @Override
    public String toString() {
        return "MemoryRecords(size=" + sizeInBytes() +
                ", buffer=" + buffer +
                ")";
    }

    @Override
    public boolean equals(Object o) {
        if (this == o)
            return true;
        if (o == null || getClass() != o.getClass())
            return false;

        MemoryRecords that = (MemoryRecords) o;

        return buffer.equals(that.buffer);
    }

    @Override
    public int hashCode() {
        return buffer.hashCode();
    }

    /**
     * Abstract base class for record filtering during log compaction and retention.
     *
     * <p>Subclasses implement batch-level and record-level filtering decisions. Filters are
     * applied in two phases:
     * <ol>
     *   <li>Batch-level decision via {@link #checkBatchRetention(RecordBatch)}</li>
     *   <li>Record-level decision via {@link #shouldRetainRecord(RecordBatch, Record)}</li>
     * </ol>
     *
     * <p><b>Thread Safety:</b> Filter implementations are not thread-safe. A single filter
     * instance should not be used from multiple threads concurrently.
     *
     * @see BatchRetention
     */
    public abstract static class RecordFilter {
        /**
         * The current time in milliseconds, used for time-based retention decisions.
         */
        public final long currentTime;

        /**
         * The delete retention time in milliseconds. Used to calculate delete horizon
         * timestamps for tombstones and transaction markers.
         */
        public final long deleteRetentionMs;

        /**
         * Create a {@code RecordFilter} with the given parameters.
         *
         * @param currentTime The current time in milliseconds
         * @param deleteRetentionMs The delete retention time in milliseconds
         */
        public RecordFilter(final long currentTime, final long deleteRetentionMs) {
            this.currentTime = currentTime;
            this.deleteRetentionMs = deleteRetentionMs;
        }

        /**
         * Result of a batch-level retention check.
         */
        public static class BatchRetentionResult {
            /**
             * The batch retention decision.
             */
            public final BatchRetention batchRetention;

            /**
             * Whether the batch contains an empty transaction marker.
             */
            public final boolean containsMarkerForEmptyTxn;

            /**
             * Create a {@code BatchRetentionResult}.
             *
             * @param batchRetention The retention decision
             * @param containsMarkerForEmptyTxn Whether the batch contains an empty txn marker
             */
            public BatchRetentionResult(final BatchRetention batchRetention,
                                        final boolean containsMarkerForEmptyTxn) {
                this.batchRetention = batchRetention;
                this.containsMarkerForEmptyTxn = containsMarkerForEmptyTxn;
            }
        }

        /**
         * Batch retention decisions.
         */
        public enum BatchRetention {
            /**
             * Delete the entire batch without inspecting individual records.
             */
            DELETE,

            /**
             * Retain the batch even if it becomes empty after record filtering.
             */
            RETAIN_EMPTY,

            /**
             * Delete the batch only if it is empty after record filtering.
             */
            DELETE_EMPTY
        }

        /**
         * Check whether the full batch can be discarded (i.e. whether we even need to
         * check the records individually).
         *
         * <p>This method is called first for each batch. If it returns {@link BatchRetention#DELETE},
         * the batch is skipped entirely and {@link #shouldRetainRecord(RecordBatch, Record)}
         * is not called for any records in this batch.
         *
         * @param batch The batch to check
         * @return A {@code BatchRetentionResult} with the retention decision and transaction marker info
         */
        protected abstract BatchRetentionResult checkBatchRetention(RecordBatch batch);

        /**
         * Check whether a record should be retained in the log.
         *
         * <p>This method is called for each record in batches that were not explicitly
         * discarded with {@link BatchRetention#DELETE}.
         *
         * <p>Note that {@link #checkBatchRetention(RecordBatch)} is used prior to checking
         * individual record retention.
         *
         * @param recordBatch The batch containing the record
         * @param record The record to check
         * @return {@code true} if the record should be retained, {@code false} otherwise
         */
        protected abstract boolean shouldRetainRecord(RecordBatch recordBatch, Record record);
    }

    /**
     * Summary of a filtering operation.
     *
     * <p>This class provides metrics about which records/batches were processed and retained
     * during filtering. It is used for logging and monitoring compaction progress.
     */
    public static class FilterResult {
        /**
         * The output buffer containing filtered records.
         */
        private ByteBuffer outputBuffer;

        /**
         * The number of records/messages read from all batches.
         */
        private int messagesRead = 0;

        /**
         * The total bytes read (including from discarded batches).
         */
        private int bytesRead = 0;

        /**
         * The number of records retained after filtering.
         */
        private int messagesRetained = 0;

        /**
         * The total bytes retained after filtering.
         */
        private int bytesRetained = 0;

        /**
         * The maximum offset across all retained records.
         */
        private long maxOffset = -1L;

        /**
         * The maximum timestamp across all retained records.
         */
        private long maxTimestamp = RecordBatch.NO_TIMESTAMP;

        /**
         * The offset of the record with the maximum timestamp (shallow offset, pre-compaction).
         */
        private long shallowOffsetOfMaxTimestamp = -1L;

        private FilterResult(ByteBuffer outputBuffer) {
            this.outputBuffer = outputBuffer;
        }

        private void updateRetainedBatchMetadata(MutableRecordBatch retainedBatch, int numMessagesInBatch, boolean headerOnly) {
            int bytesRetained = headerOnly ? DefaultRecordBatch.RECORD_BATCH_OVERHEAD : retainedBatch.sizeInBytes();
            updateRetainedBatchMetadata(retainedBatch.maxTimestamp(), retainedBatch.lastOffset(),
                    retainedBatch.lastOffset(), numMessagesInBatch, bytesRetained);
        }

        private void updateRetainedBatchMetadata(long maxTimestamp, long shallowOffsetOfMaxTimestamp, long maxOffset,
                                                 int messagesRetained, int bytesRetained) {
            validateBatchMetadata(maxTimestamp, shallowOffsetOfMaxTimestamp, maxOffset);
            if (maxTimestamp > this.maxTimestamp) {
                this.maxTimestamp = maxTimestamp;
                this.shallowOffsetOfMaxTimestamp = shallowOffsetOfMaxTimestamp;
            }
            this.maxOffset = Math.max(maxOffset, this.maxOffset);
            this.messagesRetained += messagesRetained;
            this.bytesRetained += bytesRetained;
        }

        private void validateBatchMetadata(long maxTimestamp, long shallowOffsetOfMaxTimestamp, long maxOffset) {
            if (maxTimestamp != RecordBatch.NO_TIMESTAMP && shallowOffsetOfMaxTimestamp < 0)
                throw new IllegalArgumentException("shallowOffset undefined for maximum timestamp " + maxTimestamp);
            if (maxOffset < 0)
                throw new IllegalArgumentException("maxOffset undefined");
        }

        /**
         * Get the output buffer containing filtered records.
         *
         * @return The output buffer
         */
        public ByteBuffer outputBuffer() {
            return outputBuffer;
        }

        /**
         * Get the total number of messages read during filtering.
         *
         * @return The number of messages read
         */
        public int messagesRead() {
            return messagesRead;
        }

        /**
         * Get the total bytes read during filtering (including discarded batches).
         *
         * @return The number of bytes read
         */
        public int bytesRead() {
            return bytesRead;
        }

        /**
         * Get the total number of messages retained after filtering.
         *
         * @return The number of messages retained
         */
        public int messagesRetained() {
            return messagesRetained;
        }

        /**
         * Get the total bytes retained after filtering.
         *
         * @return The number of bytes retained
         */
        public int bytesRetained() {
            return bytesRetained;
        }

        /**
         * Get the maximum offset of retained records.
         *
         * @return The maximum offset, or -1L if no records were retained
         */
        public long maxOffset() {
            return maxOffset;
        }

        /**
         * Get the maximum timestamp of retained records.
         *
         * @return The maximum timestamp
         */
        public long maxTimestamp() {
            return maxTimestamp;
        }

        /**
         * Get the shallow offset of the record with the maximum timestamp.
         *
         * @return The shallow offset of max timestamp record, or -1L if not set
         */
        public long shallowOffsetOfMaxTimestamp() {
            return shallowOffsetOfMaxTimestamp;
        }
    }

